import React from 'react';
import styles from '../styles/Options.module.css';

const Options = ({ options, selectedOption, setSelectedOption }) => {
  return (
    <div className={styles.optionsContainer}>
      {options.map((option, index) => (
        <button 
          key={index} 
          className={`${styles.optionButton} ${selectedOption === option ? styles.selected : ''}`} // Thêm class nếu lựa chọn được chọn
          onClick={() => setSelectedOption(option)} // Cập nhật lựa chọn khi nhấn
        >
          {option}
        </button>
      ))}
    </div>
  );
};

export default Options;
